import{_ as i,C as s,o as t,c as r,a2 as n,b as l,w as a,a as c,E as d,a3 as u}from"./chunks/framework.B72_uj9U.js";const y=JSON.parse('{"title":"Capy — Context Management","description":"","frontmatter":{},"headers":[],"relativePath":"research/agents/capy/context-management.md","filePath":"research/agents/capy/context-management.md"}'),p={name:"research/agents/capy/context-management.md"};function h(g,e,m,x,C,f){const o=s("Mermaid");return t(),r("div",null,[e[1]||(e[1]=n('<h1 id="capy-—-context-management" tabindex="-1">Capy — Context Management <a class="header-anchor" href="#capy-—-context-management" aria-label="Permalink to &quot;Capy — Context Management&quot;">​</a></h1><blockquote><p>The spec is the context handoff mechanism between Captain and Build. Limited internal details are publicly available.</p></blockquote><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Capy&#39;s context management strategy is fundamentally shaped by its <strong>two-agent architecture</strong>. Rather than managing a single, growing context window (as terminal agents like Claude Code or Aider must), Capy uses the <strong>spec as a context boundary</strong> — a structured handoff document that transfers relevant knowledge from Captain to Build without carrying over the full planning conversation.</p><h2 id="the-spec-as-context-handoff" tabindex="-1">The Spec as Context Handoff <a class="header-anchor" href="#the-spec-as-context-handoff" aria-label="Permalink to &quot;The Spec as Context Handoff&quot;">​</a></h2><p>The central context management pattern in Capy is the <strong>spec document</strong> produced by Captain:</p>',6)),(t(),l(u,null,{default:a(()=>[d(o,{id:"mermaid-20",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20CC%5B%22Captain's%20Context%5Cntask%20description%20%C2%B7%20codebase%20exploration%5Cnclarification%20Q%26A%20%C2%B7%20research%20findings%22%5D%0A%20%20%20%20SPEC%5B%22THE%20SPEC%5Cncompact%20%C2%B7%20structured%20%C2%B7%20actionable%20document%22%5D%0A%20%20%20%20BC%5B%22Build's%20Context%5Cnspec%20%C2%B7%20full%20codebase%20access%20%C2%B7%20VM%20state%5Cn%E2%80%94%20does%20NOT%20receive%3A%20exploration%20trace%2C%5CnQ%26A%20conversation%2C%20research%20raw%20materials%20%E2%80%94%22%5D%0A%0A%20%20%20%20CC%20--%3E%7C%22distilled%20into%22%7C%20SPEC%20--%3E%7C%22handed%20off%20to%22%7C%20BC%0A"})]),fallback:a(()=>[...e[0]||(e[0]=[c(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=n('<p>This is architecturally significant because:</p><ol><li><p><strong>Context compression is forced</strong>: Captain must distill all relevant information into a spec. Irrelevant exploration paths, dead ends, and verbose clarification dialogues are naturally excluded.</p></li><li><p><strong>Build starts fresh</strong>: Build doesn&#39;t inherit Captain&#39;s growing context window. It receives a clean, focused document plus codebase access. This means Build&#39;s context budget is spent on code, not on planning history.</p></li><li><p><strong>Separation prevents pollution</strong>: In single-agent systems, planning context (research, exploration, user back-and-forth) competes with execution context (code, test output, error messages) for the same finite window. The Captain/Build split eliminates this competition.</p></li></ol><h2 id="captain-s-context-during-planning" tabindex="-1">Captain&#39;s Context During Planning <a class="header-anchor" href="#captain-s-context-during-planning" aria-label="Permalink to &quot;Captain&#39;s Context During Planning&quot;">​</a></h2><p>During the planning phase, Captain&#39;s context includes:</p><ul><li><strong>User&#39;s task description</strong>: The original request and any referenced issues</li><li><strong>Codebase content</strong>: Files and directories Captain reads during exploration</li><li><strong>Clarification history</strong>: The Q&amp;A dialogue with the user</li><li><strong>Research materials</strong>: Documentation, dependencies, patterns discovered</li></ul><p>Captain must manage this growing context to produce a useful spec. The exact mechanisms (compaction, summarization, selective retrieval) are not publicly documented.</p><h2 id="build-s-context-during-execution" tabindex="-1">Build&#39;s Context During Execution <a class="header-anchor" href="#build-s-context-during-execution" aria-label="Permalink to &quot;Build&#39;s Context During Execution&quot;">​</a></h2><p>During execution, Build&#39;s context includes:</p><ul><li><strong>The spec</strong>: The structured document from Captain — this is the primary context</li><li><strong>Codebase state</strong>: Files being edited, test outputs, build results</li><li><strong>VM state</strong>: Installed packages, environment variables, running processes</li></ul><p>Build operates <strong>asynchronously and autonomously</strong>, so its context management must handle the full execution lifecycle without human intervention. If Build runs into issues, it must resolve them using only the spec and codebase — it cannot request more context from the user.</p><h2 id="codebase-exploration" tabindex="-1">Codebase Exploration <a class="header-anchor" href="#codebase-exploration" aria-label="Permalink to &quot;Codebase Exploration&quot;">​</a></h2><p>Both agents need to understand the codebase, but at different phases:</p><table tabindex="0"><thead><tr><th>Aspect</th><th>Captain</th><th>Build</th></tr></thead><tbody><tr><td><strong>When</strong></td><td>During planning</td><td>During execution</td></tr><tr><td><strong>Purpose</strong></td><td>Understand architecture for spec writing</td><td>Navigate code for implementation</td></tr><tr><td><strong>Depth</strong></td><td>Broad exploration of patterns and structure</td><td>Focused on files being modified</td></tr><tr><td><strong>Output</strong></td><td>Informs the spec</td><td>Informs code edits</td></tr></tbody></table><h2 id="task-level-isolation" tabindex="-1">Task-Level Isolation <a class="header-anchor" href="#task-level-isolation" aria-label="Permalink to &quot;Task-Level Isolation&quot;">​</a></h2><p>Each task in Capy operates in complete isolation:</p><ul><li><strong>Separate git worktree</strong>: No file-level conflicts between parallel tasks</li><li><strong>Separate VM</strong>: No process-level conflicts</li><li><strong>Separate context</strong>: No context contamination between tasks</li></ul><p>This means parallel tasks don&#39;t share context at all — each Captain/Build pair operates independently.</p><h2 id="what-s-not-publicly-known" tabindex="-1">What&#39;s Not Publicly Known <a class="header-anchor" href="#what-s-not-publicly-known" aria-label="Permalink to &quot;What&#39;s Not Publicly Known&quot;">​</a></h2><ul><li>Exact format and structure of spec documents</li><li>Whether Captain uses any form of RAG or embedding-based retrieval</li><li>Context window sizes or compaction strategies</li><li>How Build handles context overflow during long execution runs</li><li>Whether there&#39;s any context sharing mechanism between related tasks</li><li>Caching or persistence of codebase exploration results</li></ul>',19))])}const w=i(p,[["render",h]]);export{y as __pageData,w as default};
